__kernel void dynproc_kernel(const int iteration,
                             __global const int* gpuWall,
                             __global int* gpuResultSrc,
                             __global int* gpuResultDst,
                             const int cols,
                             const int rows,
                             const int startStep,
                             const int borderCols,
                             const int halo,
                             __local int* prev,
                             __local int* result,
                             __global int* outputBuffer)
{
    size_t gid = get_global_id(0);
    if (gid != 0) {
        return;
    }

    (void)rows;
    (void)borderCols;
    (void)halo;
    (void)prev;
    (void)result;

    __global int* src = gpuResultSrc;
    __global int* dst = gpuResultDst;

    for (int s = 0; s < iteration; s++) {
        int wallOffset = (startStep + s) * cols;

        for (int n = 0; n < cols; n++) {
            int minVal = src[n];
            if (n > 0 && src[n - 1] < minVal) {
                minVal = src[n - 1];
            }
            if (n < cols - 1 && src[n + 1] < minVal) {
                minVal = src[n + 1];
            }
            dst[n] = gpuWall[wallOffset + n] + minVal;
        }

        if (s != iteration - 1) {
            __global int* temp = src;
            src = dst;
            dst = temp;
        }
    }

    if ((iteration & 1) == 0) {
        for (int n = 0; n < cols; n++) {
            gpuResultDst[n] = gpuResultSrc[n];
        }
    }

    if (outputBuffer) {
        outputBuffer[0] = 0;
    }
}
